transforms.code:
rows = value or []
r = rows[0] if rows else {}
return {"Id": r.get("Id"), "ItemId": r.get("ItemId"), "ItemPartNumber": r.get("ItemPartNumber") or "", "ItemDescription": r.get("ItemDescription") or "", "AccumulatedParts": r.get("AccumulatedParts") or 0, "TargetParts": r.get("TargetParts") or 0, "ClosedTrays": r.get("ClosedTrays") or 0, "TraysPerContainer": r.get("TraysPerContainer") or 0, "PartsPerTray": r.get("PartsPerTray") or 0, "IsSerialized": r.get("IsSerialized") or False, "ClosureMethod": r.get("ClosureMethod") or ""}

onChange.script:
# Auto-populate from the part's container config: prefill the parts-in-tray
# field with PartsPerTray (only into an EMPTY field - never overwrite input).
cfg = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.fgConfig) or {}
ppt = cfg.get("PartsPerTray")
d = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.draft) or {}
if ppt and d.get("partsCount") in (None, ""):
	self.view.custom.draft = {"partsCount": ppt, "trayPosition": d.get("trayPosition") or ""}

transforms.code:
rows = value or []
if not rows:
	return "(none at this cell)"
totals = {}
order = []
for r in rows:
	k = r.get("ItemPartNumber") or "?"
	if k not in totals:
		totals[k] = 0
		order.append(k)
	totals[k] = totals[k] + (r.get("PieceCount") or 0)
return "   |   ".join(["%s: %d pcs" % (k, totals[k]) for k in order])

config.script:
result = BlueRidge.Workorder.Assembly.handleTrayComplete(self.view.custom.container, self.view.custom.draft, self.view.custom.selectedFinishedGoodItemId, self.session.custom.cell.locationId, self.session.custom.closureMethod)
BlueRidge.Common.Ui.notifyResult(result, "Tray completed - FG LOT minted")
if result and result.get("Status"):
	# Re-prime the next tray from the part's config (the fgConfig onChange only
	# fires when the CONFIG changes, so a same-container tray 2 would stay blank).
	cfg = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.fgConfig) or {}
	self.view.custom.draft = {"trayPosition": "", "partsCount": cfg.get("PartsPerTray") or ""}
	self.view.custom.refreshToken = (self.view.custom.refreshToken or 0) + 1
	if result.get("ContainerFull"):
		BlueRidge.Common.Notify.toast("Container full", "Press Complete to ship.", "info")

# Dedicated-flavor context (FDS-02-010): bind the cell to the terminal's parent line.
t = self.session.custom.terminal
if t and t.get("zoneLocationId"):
	self.session.custom.cell = {"locationId": t.get("zoneLocationId"), "code": t.get("zoneName") or "", "name": t.get("zoneName") or ""}
	# Pre-select the recommended finished good (best BOM match against ready line inventory).
	self.view.custom.selectedFinishedGoodItemId = BlueRidge.Workorder.Assembly.getRecommendedFinishedGoodId(t.get("zoneLocationId"))
try:
	self.session.custom.presence.policy = "confirm"
except:
	self.session.custom.presence = {"policy": "confirm"}
if not self.session.custom.appUserId:
	system.perspective.openPopup("mpp-initials", "BlueRidge/Components/Popups/InitialsEntry", params={"popupId": "mpp-initials"}, modal=True, showCloseIcon=False, overlayDismiss=False)
